package com.museumheist.game.progress;import com.museumheist.game.entity.PowerUp;import org.junit.Test;import static org.junit.Assert.*;public class LoadoutSelectionTest{@Test public void two(){LoadoutSelection s=new LoadoutSelection();assertEquals(LoadoutSelection.ToggleResult.SELECTED,s.toggle(PowerUp.Type.CLOAK));assertEquals(LoadoutSelection.ToggleResult.SELECTED,s.toggle(PowerUp.Type.SPEED));assertEquals(2,s.size());}@Test public void third(){LoadoutSelection s=new LoadoutSelection();s.toggle(PowerUp.Type.CLOAK);s.toggle(PowerUp.Type.SPEED);assertEquals(LoadoutSelection.ToggleResult.FULL,s.toggle(PowerUp.Type.JAMMER));}@Test public void remove(){LoadoutSelection s=new LoadoutSelection();s.toggle(PowerUp.Type.CLOAK);s.toggle(PowerUp.Type.SPEED);s.toggle(PowerUp.Type.CLOAK);assertEquals(PowerUp.Type.SPEED,s.get(0));assertNull(s.get(1));}@Test public void restore(){LoadoutSelection s=new LoadoutSelection();s.restore(new PowerUp.Type[]{PowerUp.Type.PHASE,PowerUp.Type.PHASE});assertEquals(1,s.size());}@Test public void noDuplicate(){LoadoutSelection s=new LoadoutSelection();assertTrue(s.selectIfSpace(PowerUp.Type.DECOY));assertFalse(s.selectIfSpace(PowerUp.Type.DECOY));}@Test public void copy(){LoadoutSelection s=new LoadoutSelection();s.toggle(PowerUp.Type.JAMMER);PowerUp.Type[]a={PowerUp.Type.CLOAK,PowerUp.Type.SPEED};s.copyTo(a);assertEquals(PowerUp.Type.JAMMER,a[0]);assertNull(a[1]);}}